import { useEffect, useState, useCallback, useRef } from "react";
import { Link } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { MapPin, UtensilsCrossed, HandMetal, ChevronDown, ChevronUp, Loader2 } from "lucide-react";
import { calculateDistance } from "@/lib/geolocation";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useAutoTranslateNames } from "@/hooks/useAutoTranslateNames";

interface NearbyRestaurant {
  id: string;
  name: string;
  name_en?: string;
  name_pt?: string;
  image_url?: string | null;
  type_en?: string[];
  lat: number;
  lng: number;
  store_level?: string;
  distance?: number;
}

interface NearbyRestaurantsSectionProps {
  lat: number;
  lng: number;
  currentRestaurantId: string;
  landmarkName?: string;
}

const RADIUS_KM = 3;
const PREVIEW_COUNT = 7;
const PAGE_SIZE = 12;

export const NearbyRestaurantsSection = ({ lat, lng, currentRestaurantId, landmarkName }: NearbyRestaurantsSectionProps) => {
  const { t } = useTranslation();
  const { getLocalizedField, getNameWithOriginal } = useLocalizedContent();

  // Preview data (horizontal scroll, first 7)
  const [previewRestaurants, setPreviewRestaurants] = useState<NearbyRestaurant[]>([]);
  const [loading, setLoading] = useState(true);

  // Expanded state
  const [expanded, setExpanded] = useState(false);
  const [allRestaurants, setAllRestaurants] = useState<NearbyRestaurant[]>([]);
  const [allLoading, setAllLoading] = useState(false);
  const [allLoaded, setAllLoaded] = useState(false);
  const [displayCount, setDisplayCount] = useState(PAGE_SIZE);
  const [loadingMore, setLoadingMore] = useState(false);
  const scrollSentinelRef = useRef<HTMLDivElement>(null);

  // Fetch preview (first 7)
  useEffect(() => {
    if (!lat || !lng) return;
    let cancelled = false;

    const fetchNearby = async () => {
      setLoading(true);
      const degreeOffset = RADIUS_KM / 111;
      const { data, error } = await supabase
        .from("restaurants")
        .select("id,name,name_en,name_pt,image_url,type_en,lat,lng,store_level,address")
        .eq("visible", true)
        .eq("archived", false)
        .neq("template", "landmark")
        .gte("lat", lat - degreeOffset)
        .lte("lat", lat + degreeOffset)
        .gte("lng", lng - degreeOffset)
        .lte("lng", lng + degreeOffset)
        .limit(500);

      if (cancelled || error) {
        setLoading(false);
        return;
      }

      const seenIds = new Set<string>();
      const seenAddresses = new Set<string>();
      const withDistance = (data || [])
        .filter((r) => {
          if (r.id === currentRestaurantId || seenIds.has(r.id)) return false;
          seenIds.add(r.id);
          // Deduplicate by address — one physical address = one restaurant
          const addr = ((r as any).address || '').trim().toLowerCase();
          if (addr && seenAddresses.has(addr)) return false;
          if (addr) seenAddresses.add(addr);
          return true;
        })
        .map((r) => ({
          ...r,
          distance: calculateDistance(lat, lng, r.lat, r.lng),
        }))
        .filter((r) => r.distance <= RADIUS_KM)
        .sort((a, b) => a.distance - b.distance);

      if (!cancelled) {
        setPreviewRestaurants(withDistance.slice(0, PREVIEW_COUNT));
        // Cache all results for expand
        setAllRestaurants(withDistance);
        setAllLoaded(true);
        setLoading(false);
      }
    };

    fetchNearby();
    return () => { cancelled = true; };
  }, [lat, lng, currentRestaurantId]);

  // Auto-translate names for displayed restaurants
  const displayedRestaurants = expanded ? allRestaurants.slice(0, displayCount) : previewRestaurants;
  const [nameTranslations, setNameTranslations] = useState<Record<string, string> | null>(null);
  useAutoTranslateNames(displayedRestaurants, setNameTranslations);

  const getDisplayName = (r: NearbyRestaurant) => {
    const { displayName, originalName, showDual } = getNameWithOriginal(r);
    // If auto-translated name is available, use it as the display name
    if (nameTranslations?.[r.id]) {
      const translated = nameTranslations[r.id].split('\n')[0];
      const orig = r.name || "";
      if (translated.trim().toLowerCase() !== orig.trim().toLowerCase() && orig) {
        return `${translated} · ${orig}`;
      }
      return translated;
    }
    if (showDual) {
      return `${displayName} · ${originalName}`;
    }
    return displayName;
  };

  // Infinite scroll observer
  useEffect(() => {
    if (!expanded || !scrollSentinelRef.current) return;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && displayCount < allRestaurants.length) {
          setLoadingMore(true);
          // Simulate small delay for smooth UX
          setTimeout(() => {
            setDisplayCount((prev) => Math.min(prev + PAGE_SIZE, allRestaurants.length));
            setLoadingMore(false);
          }, 300);
        }
      },
      { rootMargin: "200px" }
    );

    observer.observe(scrollSentinelRef.current);
    return () => observer.disconnect();
  }, [expanded, displayCount, allRestaurants.length]);

  const handleExpand = () => {
    setExpanded(true);
    setDisplayCount(PAGE_SIZE);
  };

  const handleCollapse = () => {
    setExpanded(false);
    setDisplayCount(PAGE_SIZE);
  };

  if (loading) {
    return (
      <section className="space-y-4">
        <div className="flex items-center gap-3">
          <div className="p-2.5 rounded-xl bg-accent">
            <UtensilsCrossed className="w-5 h-5 text-accent-foreground" />
          </div>
          <div>
            <Skeleton className="h-6 w-40" />
            <Skeleton className="h-4 w-56 mt-1" />
          </div>
        </div>
        <div className="flex gap-3 overflow-x-auto pb-2">
          {Array.from({ length: 4 }).map((_, i) => (
            <div key={i} className="shrink-0 w-[160px]">
              <Skeleton className="h-[120px] w-full rounded-xl" />
              <Skeleton className="h-4 w-24 mt-2" />
              <Skeleton className="h-3 w-16 mt-1" />
            </div>
          ))}
        </div>
      </section>
    );
  }

  if (previewRestaurants.length === 0) return null;

  const hasMore = allRestaurants.length > PREVIEW_COUNT;

  return (
    <section className="space-y-4">
      {/* Header */}
      <div className="flex items-center gap-3">
        <div className="p-2.5 rounded-xl bg-accent">
          <UtensilsCrossed className="w-5 h-5 text-accent-foreground" />
        </div>
        <div>
          <h2 className="text-xl font-bold text-foreground">
            {t("landmark.nearbyRestaurants")}
          </h2>
          <p className="text-sm text-muted-foreground">
            {t("landmark.nearbyRestaurantsSubtitle")}
            {allRestaurants.length > 0 && (
              <span className="ml-1">({allRestaurants.length})</span>
            )}
          </p>
        </div>
      </div>

      {!expanded ? (
        <>
          {/* Horizontal preview scroll */}
          <div className="flex gap-3 overflow-x-auto pb-2 -mx-1 px-1 scrollbar-hide">
            {previewRestaurants.map((r) => (
              <RestaurantPreviewCard key={r.id} restaurant={r} getDisplayName={getDisplayName} t={t} />
            ))}
          </div>

          {/* Expand button */}
          {hasMore && (
            <div className="flex justify-center pt-1">
              <Button
                variant="outline"
                size="sm"
                onClick={handleExpand}
                className="rounded-full gap-1.5 text-primary border-primary/20 hover:bg-primary/10"
              >
                <ChevronDown className="w-3.5 h-3.5" />
                {t("landmark.viewAllNearby")} ({allRestaurants.length})
              </Button>
            </div>
          )}
        </>
      ) : (
        <>
          {/* Expanded grid using same preview cards in scrollable container */}
          <div className="max-h-[60vh] overflow-y-auto pb-2 scrollbar-hide">
            <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3">
              {displayedRestaurants.map((r) => (
                <RestaurantPreviewCard key={r.id} restaurant={r} getDisplayName={getDisplayName} t={t} className="group" />
              ))}
            </div>

            {/* Infinite scroll sentinel */}
            {displayCount < allRestaurants.length && (
              <div ref={scrollSentinelRef} className="flex justify-center py-3">
                {loadingMore && (
                  <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
                )}
              </div>
            )}

            {/* Loaded all indicator */}
            {displayCount >= allRestaurants.length && allRestaurants.length > PAGE_SIZE && (
              <p className="text-center text-xs text-muted-foreground py-2">
                {t("common.allLoaded", "All loaded")}
              </p>
            )}
          </div>

          {/* Collapse button */}
          <div className="flex justify-center pt-1">
            <Button
              variant="outline"
              size="sm"
              onClick={handleCollapse}
              className="rounded-full gap-1.5 text-primary border-primary/20 hover:bg-primary/10"
            >
              <ChevronUp className="w-3.5 h-3.5" />
              {t("common.collapse", "Collapse")}
            </Button>
          </div>
        </>
      )}
    </section>
  );
};

/** Horizontal preview card (compact) */
const RestaurantPreviewCard = ({
  restaurant: r,
  getDisplayName,
  t,
  className,
}: {
  restaurant: NearbyRestaurant;
  getDisplayName: (r: NearbyRestaurant) => string;
  t: (key: string) => string;
  className?: string;
}) => (
  <Link
    to={`/restaurant/${r.id}`}
    className={className || "shrink-0 w-[160px] group"}
  >
    <div className="relative rounded-xl overflow-hidden aspect-[4/3] bg-muted">
      {r.image_url ? (
        <img
          src={r.image_url}
          alt={getDisplayName(r)}
          className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
          loading="lazy"
        />
      ) : (
        <div className="w-full h-full flex items-center justify-center">
          <UtensilsCrossed className="w-8 h-8 text-muted-foreground/40" />
        </div>
      )}
      {r.store_level !== 'complete' && (
        <Badge
          variant="secondary"
          className="absolute top-1.5 left-1.5 text-[10px] px-1.5 py-0.5 bg-background/80 text-muted-foreground border-0 gap-1"
        >
          <HandMetal className="w-3 h-3" />
          {t("restaurants.unclaimedStore")}
        </Badge>
      )}
    </div>
    <div className="mt-2 px-0.5">
      <p className="text-sm font-medium text-foreground truncate">
        {getDisplayName(r)}
      </p>
      <div className="flex items-center gap-1 mt-0.5 text-xs text-muted-foreground">
        <MapPin className="w-3 h-3 shrink-0" />
        <span>{r.distance !== undefined ? `${r.distance.toFixed(1)} km` : ""}</span>
        {r.type_en?.[0] && (
          <>
            <span className="mx-0.5">·</span>
            <span className="truncate">{r.type_en[0]}</span>
          </>
        )}
      </div>
    </div>
  </Link>
);

/** Vertical list card (full width) */
const RestaurantListCard = ({
  restaurant: r,
  getDisplayName,
  t,
}: {
  restaurant: NearbyRestaurant;
  getDisplayName: (r: NearbyRestaurant) => string;
  t: (key: string) => string;
}) => (
  <Link
    to={`/restaurant/${r.id}`}
    className="flex gap-3 p-2 rounded-xl hover:bg-accent/50 transition-colors group"
  >
    {/* Thumbnail */}
    <div className="relative shrink-0 w-20 h-20 rounded-lg overflow-hidden bg-muted">
      {r.image_url ? (
        <img
          src={r.image_url}
          alt={getDisplayName(r)}
          className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
          loading="lazy"
        />
      ) : (
        <div className="w-full h-full flex items-center justify-center">
          <UtensilsCrossed className="w-5 h-5 text-muted-foreground/40" />
        </div>
      )}
    </div>

    {/* Info */}
    <div className="flex-1 min-w-0 flex flex-col justify-center">
      <p className="text-sm font-medium text-foreground truncate">
        {getDisplayName(r)}
      </p>
      <div className="flex items-center gap-1.5 mt-1 text-xs text-muted-foreground">
        <MapPin className="w-3 h-3 shrink-0" />
        <span className="font-medium text-primary">
          {r.distance !== undefined ? `${r.distance.toFixed(1)} km` : ""}
        </span>
        {r.type_en?.[0] && (
          <>
            <span>·</span>
            <span className="truncate">{r.type_en[0]}</span>
          </>
        )}
      </div>
      {r.store_level !== 'complete' && (
        <Badge
          variant="secondary"
          className="mt-1 w-fit text-[10px] px-1.5 py-0 bg-muted text-muted-foreground border-0 gap-1"
        >
          <HandMetal className="w-3 h-3" />
          {t("restaurants.unclaimedStore")}
        </Badge>
      )}
    </div>
  </Link>
);
