import { useState } from "react";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Quote, ChevronRight, Sparkles, Languages, Loader2, RotateCcw } from "lucide-react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";

interface OwnerBioDrawerProps {
  ownerBio: string;
  ownerName: string;
  ownerAvatarUrl?: string;
  avatarFallback: string;
}

export const OwnerBioDrawer = ({
  ownerBio,
  ownerName,
  ownerAvatarUrl,
  avatarFallback,
}: OwnerBioDrawerProps) => {
  const { t, i18n } = useTranslation();
  const [translation, setTranslation] = useState<{ text: string; show: boolean } | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);

  const handleTranslate = async () => {
    if (translation) {
      setTranslation(prev => prev ? { ...prev, show: !prev.show } : null);
      return;
    }
    if (!ownerBio) return;
    setIsTranslating(true);
    try {
      const { data, error } = await supabase.functions.invoke("translate-content", {
        body: { text: ownerBio, targetLang: i18n.language },
      });
      if (!error && data?.translatedText) {
        setTranslation({ text: data.translatedText, show: true });
      }
    } catch {}
    setIsTranslating(false);
  };

  const displayBio = translation?.show ? translation.text : ownerBio;

  return (
    <Sheet>
      <SheetTrigger asChild>
        <Button 
          variant="ghost" 
          size="sm" 
          className="text-primary hover:text-primary/80 p-0 h-auto font-medium gap-1"
        >
          {t("common.viewAll", "查看全部")}
          <ChevronRight className="w-4 h-4" />
        </Button>
      </SheetTrigger>
      <SheetContent 
        side="bottom" 
        className="max-h-[85dvh] rounded-t-[10px] p-0 flex flex-col overflow-hidden"
        onPointerDownOutside={(e) => e.preventDefault()}
      >
        <SheetHeader className="p-4 pb-2 shrink-0">
          <div className="flex items-center justify-between">
            <SheetTitle className="flex items-center gap-2 text-lg">
              <Sparkles className="w-5 h-5 text-primary" />
              {t("restaurants.ownerStory", "主理人")}
            </SheetTitle>
            <button
              onClick={handleTranslate}
              disabled={isTranslating}
              className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium transition-colors disabled:opacity-50 ${
                translation?.show
                  ? "text-primary bg-primary/10"
                  : "text-muted-foreground hover:text-primary hover:bg-primary/10"
              }`}
            >
              {isTranslating ? (
                <Loader2 className="w-3.5 h-3.5 animate-spin" />
              ) : translation?.show ? (
                <RotateCcw className="w-3.5 h-3.5" />
              ) : (
                <Languages className="w-3.5 h-3.5" />
              )}
              {isTranslating
                ? t("translate.translating", "翻译中...")
                : translation?.show
                  ? t("translate.showOriginal", "显示原文")
                  : t("translate.button", "翻译")}
            </button>
          </div>
        </SheetHeader>
        <div className="flex-1 min-h-0 overflow-y-auto overscroll-contain -webkit-overflow-scrolling-touch px-4 pb-8">
          <div className="relative max-w-2xl mx-auto">
            <Quote className="absolute -top-4 -left-2 w-12 h-12 text-primary/10 rotate-180" />
            <div className="relative z-10 pt-6 space-y-4">
              <p className="text-base md:text-lg text-foreground leading-relaxed whitespace-pre-wrap first-letter:text-4xl first-letter:font-bold first-letter:text-primary first-letter:float-left first-letter:mr-2 first-letter:mt-1">
                {displayBio}
              </p>
            </div>
            <div className="mt-8 flex items-center gap-3 pt-6 border-t">
              <div className="w-12 h-12 rounded-full overflow-hidden bg-gradient-to-br from-primary to-accent flex items-center justify-center text-primary-foreground font-bold text-lg shadow-lg">
                {ownerAvatarUrl ? (
                  <img 
                    src={ownerAvatarUrl} 
                    alt={ownerName}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  avatarFallback
                )}
              </div>
              <div className="text-left">
                <p className="font-semibold text-foreground">{ownerName}</p>
                <p className="text-xs text-muted-foreground">{t("restaurants.chef", "大厨")}</p>
              </div>
            </div>
          </div>
        </div>
      </SheetContent>
    </Sheet>
  );
};

export default OwnerBioDrawer;
